// Pega todos os itens recebidos
const items = $input.all();

// Extrai a UF (últimos 2 caracteres após o hífen)
const ufs = items
  .map(item => {
    const text = item.json.uf || item.json.cidade_origem || "";
    const match = text.match(/([A-Z]{2})$/);
    return match ? match[1] : null;
  })
  .filter(Boolean); // remove nulos

// Remove duplicadas
const ufsUnicas = [...new Set(ufs)];

// Retorna no formato original
return [
  {
    json: {
      ufs_unicas: ufsUnicas
    }
  }
];

function safe(v) {
  if (v === null || v === undefined) return "";
  return String(v);
}

// 1. Ordenar resultados pelo score final (descendente)
const sorted = [...items].sort(
  (a, b) => (b.json.score_final || 0) - (a.json.score_final || 0)
);

// 2. Identificar os extremos para a normalização (Min-Max)
const maxScore = sorted[0]?.json?.score_final || 0;
const minScore = sorted[sorted.length - 1]?.json?.score_final || 0;

return sorted.map(item => {
  const j = item.json;
  const payload = j.payload || {};
  const score = j.score_final || 0;

  let nota = 75; // Piso padrão

  // 3. Lógica de Interpolação Linear para o intervalo [75, 100]
  if (maxScore > minScore) {
    // Cálculo: Base 75 + Proporção do Score (0 a 25)
    nota = 75 + (25 * (score - minScore)) / (maxScore - minScore);
  } else if (maxScore > 0) {
    // Se todos os scores forem iguais, todos recebem a nota máxima
    nota = 100;
  }

  // 4. Conversão para INTEIRO e trava de segurança
  nota = Math.round(nota); 
  nota = Math.max(75, Math.min(100, nota));

  return {
    json: {
      id: j.id || null,
      score_final: score,
      nota: parseInt(nota), // Garante que o output seja um Number Inteiro

      cnpj: safe(payload.cnpj),
      n_exibicoes: j.n_exibicoes || 0,
      plano_categoria: j.plano_categoria || null,

      full_profile: {
        identidade: {
          nome_empresa: safe(payload.nome_empresa)
        },
        contato: {
          url_site: safe(payload.site),
          telefones: safe(payload.telefone),
          emails: safe(payload.email)
        }
      }
    }
  };
});

